mapper.select:
	SELECT COUNT(1)
  	  FROM TWORK_MST_ICSB
	 WHERE OWKEY = #{owkey}
 	   AND ICKEY = #{ickey}

	   AND	SBKEY = #{sbkey}	


 	   AND  CTKEY = #{ctkey}

mapper.update:

		UPDATE 	TWORK_MST_ICSB 
	   	   SET	ICUTTYPE = #{icunittype}
          		,UDF1 = #{udf1}
          		,UDF2 = #{udf2}
          		,UDF3 = #{udf3}
          		,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
		        ,UPDATEDATE = #{sysdate}
		        ,UPDATEURKEY = #{surkey}
		 WHERE	OWKEY = #{owkey}
		   AND	ICKEY = #{ickey}
		   AND	SBKEY = #{sbkey}

	  	   AND 	CTKEY = #{ctkey}

mapper.delete:
    UPDATE 	TWORK_MST_ICSB
	SET      DELYN 				= 'Y'
			,CLOSDATE		= #{sysdate}
    WHERE	OWKEY = #{owkey} 
	   AND 	ICKEY = #{ickey} 

	   AND	SBKEY = #{sbkey}	


 	   AND  CTKEY = #{ctkey}
